  "teach.b2Title": { uz: "Millionlarga yeting", ru: "Достигайте миллионов", en: "Reach millions" },
  "teach.b2Desc": { uz: "Butun dunyo bo‘ylab intiluvchan o‘quvchilarga ulaning.", ru: "Получите доступ к мотивированной аудитории по всему миру.", en: "Tap into a global audience of motivated learners." },
  "teach.b3Title": { uz: "Kuchli vositalar", ru: "Мощные инструменты", en: "Powerful tools" },
  "teach.b3Desc": { uz: "Videolarni yuklang, testlar tuzing va dasturingizni oson tuzing.", ru: "Загружайте видео, создавайте тесты и легко стройте программу.", en: "Upload videos, build quizzes and structure your curriculum with ease." },
  "teach.b4Title": { uz: "Marketing yordami", ru: "Маркетинговая поддержка", en: "Marketing support" },
  "teach.b4Desc": { uz: "Biz kurslaringizni platforma bo‘ylab va undan tashqarida targ‘ib qilamiz.", ru: "Мы продвигаем ваши курсы на платформе и за её пределами.", en: "We promote your courses across the platform and beyond." },
  "teach.howTitle": { uz: "Bu qanday ishlaydi", ru: "Как это работает", en: "How it works" },
  "teach.s1Title": { uz: "Kursingizni rejalashtiring", ru: "Спланируйте курс", en: "Plan your course" },
  "teach.s1Desc": { uz: "Yoqtirgan mavzuni tanlang va dasturingizni tuzing.", ru: "Выберите любимую тему и составьте программу.", en: "Pick a topic you love and outline your curriculum." },
  "teach.s2Title": { uz: "Yozib oling va yuklang", ru: "Запишите и загрузите", en: "Record & upload" },
  "teach.s2Desc": { uz: "Studiyada darslar yarating, resurslar va testlar qo‘shing.", ru: "Создавайте уроки, добавляйте ресурсы и тесты в Студии.", en: "Create lessons, add resources and build quizzes in the Studio." },
  "teach.s3Title": { uz: "Ishga tushiring va daromad oling", ru: "Запустите и зарабатывайте", en: "Launch & earn" },
  "teach.s3Desc": { uz: "Millionlab o‘quvchilarga chop eting va daromad olishni boshlang.", ru: "Опубликуйте для миллионов учащихся и начните зарабатывать.", en: "Publish to millions of learners and start earning." },
  "teach.ctaTitle": { uz: "Dunyoni ilhomlantirishga tayyormisiz?", ru: "Готовы вдохновлять мир?", en: "Ready to inspire the world?" },
  "teach.ctaSubtitle": { uz: "Boshlash bepul. Bugun Studiyada birinchi kursingizni yarating.", ru: "Начать бесплатно. Создайте первый курс в Студии сегодня.", en: "It's free to get started. Create your first course in the Studio today." },
  "teach.createCourse": { uz: "Kursingizni yarating", ru: "Создать курс", en: "Create your course" },

  // ── About ─────────────────────────────────────────────────────────────────
  "about.missionTitle": { uz: "Bizning maqsadimiz", ru: "Наша миссия", en: "Our mission" },
  "about.missionBody": { uz: "LearnHub jahon darajasidagi ta'limni istalgan joydagi har bir kishi uchun ochiq qilish maqsadida mavjud. Biz qiziquvchan o‘quvchilarni hayotni o‘zgartiradigan ko‘nikmalarni o‘rgatadigan ekspert ustozlar bilan bog‘laymiz.", ru: "LearnHub существует, чтобы сделать образование мирового уровня доступным каждому. Мы соединяем любознательных учащихся с экспертами-преподавателями, чтобы развивать навыки, меняющие жизнь.", en: "LearnHub exists to make world-class education accessible to anyone, anywhere. We connect curious learners with expert instructors to build skills that change lives." },
  "about.statLearners": { uz: "O‘quvchilar", ru: "Учащихся", en: "Learners" },
  "about.statCourses": { uz: "Kurslar", ru: "Курсов", en: "Courses" },
  "about.statCountries": { uz: "Davlatlar", ru: "Стран", en: "Countries" },
  "about.statSatisfaction": { uz: "Mamnunlik", ru: "Удовлетворённость", en: "Satisfaction" },
  "about.valuesTitle": { uz: "Biz nimaga ishonamiz", ru: "Во что мы верим", en: "What we believe" },
  "about.v1Title": { uz: "Avval o‘quvchi", ru: "Сначала учащийся", en: "Learner first" },
  "about.v1Desc": { uz: "Har bir qaror o‘quvchilarimiz uchun eng yaxshisidan boshlanadi.", ru: "Каждое решение начинается с того, что лучше для наших учащихся.", en: "Every decision starts with what's best for our learners." },
  "about.v2Title": { uz: "Umrbod qiziquvchanlik", ru: "Любопытство на всю жизнь", en: "Lifelong curiosity" },
  "about.v2Desc": { uz: "Biz o‘rganish hech qachon to‘xtamasligiga ishonamiz — biz ham.", ru: "Мы верим, что обучение никогда не прекращается — как и мы.", en: "We believe learning never stops — and neither do we." },
  "about.v3Title": { uz: "Hamma uchun ochiq", ru: "Доступно всем", en: "Accessible to all" },
  "about.v3Desc": { uz: "Sifatli ta'lim har kimning qo‘li yetadigan joyda bo‘lishi kerak.", ru: "Качественное образование должно быть доступно каждому.", en: "Quality education should be within everyone's reach." },
  "about.teamTitle": { uz: "Jamoa bilan tanishing", ru: "Знакомьтесь с командой", en: "Meet the team" },
  "about.role1": { uz: "Hammuassis va CEO", ru: "Сооснователь и CEO", en: "Co-founder & CEO" },
  "about.role2": { uz: "Hammuassis va CPO", ru: "Сооснователь и CPO", en: "Co-founder & CPO" },
  "about.role3": { uz: "Kontent rahbari", ru: "Руководитель контента", en: "Head of Content" },
  "about.role4": { uz: "O‘sish rahbari", ru: "Руководитель роста", en: "Head of Growth" },
  "about.joinTitle": { uz: "Hamjamiyatimizga qo‘shiling", ru: "Присоединяйтесь к нашему сообществу", en: "Join our community" },
  "about.joinSubtitle": { uz: "Bugun o‘rganishni yoki o‘qitishni boshlang.", ru: "Начните учиться или преподавать сегодня.", en: "Start learning or teaching today." },
  "about.becomeInstructor": { uz: "Ustoz bo‘ling", ru: "Стать преподавателем", en: "Become an instructor" },

