  "help.t3Title": { uz: "Kurslarni o‘tish", ru: "Прохождение курсов", en: "Taking courses" },
  "help.t3Desc": { uz: "Video ijro, jarayon va resurslar.", ru: "Воспроизведение видео, прогресс и ресурсы.", en: "Video playback, progress and resources." },
