  "help.t6Desc": { uz: "Kurslar yarating, o‘quvchilar va to‘lovlarni boshqaring.", ru: "Создавайте курсы, управляйте студентами и выплатами.", en: "Create courses, manage students and payouts." },
  "help.popular": { uz: "Mashhur savollar", ru: "Популярные вопросы", en: "Popular questions" },
  "help.q1": { uz: "Parolimni qanday tiklayman?", ru: "Как сбросить пароль?", en: "How do I reset my password?" },
  "help.a1": { uz: "Kirish sahifasiga o‘ting va emailga tiklash havolasini olish uchun “Parolni unutdingizmi” ni bosing.", ru: "На странице входа нажмите «Забыли пароль», чтобы получить ссылку по почте.", en: "Go to the login page and click “Forgot password” to receive a reset link by email." },
  "help.q2": { uz: "Sertifikatlarimni qayerdan topaman?", ru: "Где найти мои сертификаты?", en: "Where can I find my certificates?" },
  "help.a2": { uz: "Barcha sertifikatlar Mening ta'limim → Sertifikatlar bo‘limida.", ru: "Все сертификаты — в разделе Моё обучение → Сертификаты.", en: "All earned certificates are available under My Learning → Certificates." },
  "help.q3": { uz: "Qaytarishlar qanday ishlaydi?", ru: "Как работают возвраты?", en: "How do refunds work?" },
  "help.a3": { uz: "Biz 30 kunlik pulni qaytarish kafolatini taklif qilamiz. Xaridlar tarixidan qaytarish so‘rang.", ru: "Мы предлагаем 30-дневную гарантию возврата. Запросите возврат в истории покупок.", en: "We offer a 30-day money-back guarantee. Request a refund from your purchase history." },
  "help.q4": { uz: "Kurslarni oflayn ko‘rish uchun yuklab olsam bo‘ladimi?", ru: "Можно ли скачивать курсы для офлайн-просмотра?", en: "Can I download courses for offline viewing?" },
  "help.a4": { uz: "Oflayn ko‘rish mobil ilovalarimiz orqali Pro rejada mavjud.", ru: "Офлайн-просмотр доступен в плане Pro через наши мобильные приложения.", en: "Offline viewing is available on the Pro plan via our mobile apps." },
  "help.stillTitle": { uz: "Hali ham yordam kerakmi?", ru: "Всё ещё нужна помощь?", en: "Still need help?" },
  "help.stillDesc": { uz: "Qo‘llab-quvvatlash jamoamiz siz uchun shu yerda.", ru: "Наша команда поддержки здесь для вас.", en: "Our support team is here for you." },
  "help.contactSupport": { uz: "Qo‘llab-quvvatlashga murojaat →", ru: "Связаться с поддержкой →", en: "Contact support →" },

